import java.io.ByteArrayOutputStream;
import java.io.IOException;
import java.io.InputStream;
import java.io.OutputStream;
import java.io.RandomAccessFile;
import java.io.UnsupportedEncodingException;
import java.util.concurrent.CountDownLatch;
import java.util.concurrent.ExecutorService;
import java.util.concurrent.Executors;
import java.util.regex.Matcher;
import java.util.regex.Pattern;
import org.apache.commons.lang3.StringUtils;

public class S3Utils {

  public static final String REGION = Regions.CN_NORTH_1.getName();
  public static boolean pathStyle = true;
  public static Pattern S3_PATH_PATTERN = Pattern
      .compile("s3://(?<bucket>[^/]+)\\/(?<path>\\S*)");


  public static AmazonS3 create() {
    return create("", "", "");
  }

  public static AmazonS3 create(String accessKey, String secretKey, String endpoint) {
    AWSCredentialsProvider credentialsProvider;
    if (StringUtils.isNotEmpty(accessKey) && StringUtils.isNotEmpty(secretKey)) {
      credentialsProvider = new AWSStaticCredentialsProvider(
          new BasicAWSCredentials(accessKey, secretKey));
    } else {
      credentialsProvider = new EnvironmentVariableCredentialsProvider();
    }
    if (StringUtils.isEmpty(endpoint)) {
      endpoint = System.getenv("S3_ENDPOINT");
    }
    if (StringUtils.isEmpty(endpoint)) {
      throw new IllegalArgumentException("endpoint is null");
    }

    ClientConfiguration clientConfig = new ClientConfiguration();
    clientConfig.setProtocol(Protocol.HTTP);
    return AmazonS3ClientBuilder.standard()
        .withCredentials(credentialsProvider)
        .withClientConfiguration(clientConfig)
        .withEndpointConfiguration(
            new AwsClientBuilder.EndpointConfiguration(
                endpoint,
                REGION)).
        withPathStyleAccessEnabled(pathStyle)
        .build();
  }

  public static S3PathInfo parsePath(String input) {
    Matcher matcher = S3_PATH_PATTERN.matcher(input);
    if (matcher.matches()) {
      String bucket = matcher.group("bucket");
      String path = matcher.group("path");
      return new S3PathInfo(bucket, path);
    }
    return null;
  }

  public static S3Object getObj(AmazonS3 client, S3PathInfo inputPath) {
    GetObjectRequest gor = new GetObjectRequest(inputPath.getBucket(), inputPath.getPath());
    return client.getObject(gor);
  }

  public static InputStream getAsInputStream(AmazonS3 client, S3PathInfo inputPath) {
    GetObjectRequest gor = new GetObjectRequest(inputPath.getBucket(), inputPath.getPath());
    return client.getObject(gor).getObjectContent();
  }

  public static InputStream getAsInputStream(AmazonS3 client, String input) {
    S3PathInfo inputPath = S3Utils.parsePath(input);
    if (inputPath == null) {
      return null;
    }
    GetObjectRequest gor = new GetObjectRequest(inputPath.getBucket(), inputPath.getPath());
    return client.getObject(gor).getObjectContent();
  }

  public static boolean putString(AmazonS3 client, String output, String content) {
    S3PathInfo outputPath = S3Utils.parsePath(output);
    if (outputPath == null) {
      return false;
    }
    ObjectMetadata om = new ObjectMetadata();
    byte[] contentBytes = new byte[0];
    try {
      contentBytes = content.getBytes("UTF-8");
      ByteArrayInputStream bis = new ByteArrayInputStream(contentBytes);
      om.setContentLength(contentBytes.length);
      PutObjectRequest por = new PutObjectRequest(outputPath.getBucket(), outputPath.getPath(), bis,
          om);
      PutObjectResult res = client.putObject(por);
      return true;
    } catch (UnsupportedEncodingException e) {
      e.printStackTrace();
      return false;
    }
  }

  public static byte[] readInputStream(InputStream inputStream) {
    ByteArrayOutputStream outStream = new ByteArrayOutputStream();
    is2os(inputStream, outStream);
    return outStream.toByteArray();
  }

  public static boolean is2os(InputStream inputStream, OutputStream outStream) {
    byte[] buffer = new byte[1024];
    int length;
    try {
      while ((length = inputStream.read(buffer)) != -1) {
        outStream.write(buffer, 0, length);
      }
      return true;
    } catch (IOException e) {
      e.printStackTrace();
      return false;
    }
  }

  public static boolean put(AmazonS3 client, String output, InputStream is) {
    S3PathInfo outputPath = S3Utils.parsePath(output);
    if (outputPath == null) {
      return false;
    }
    ObjectMetadata om = new ObjectMetadata();
    byte[] contentBytes;
    try {
      contentBytes = readInputStream(is);
      ByteArrayInputStream bis = new ByteArrayInputStream(contentBytes);
      om.setContentLength(contentBytes.length);
      PutObjectRequest por = new PutObjectRequest(outputPath.getBucket(), outputPath.getPath(), bis,
          om);
      PutObjectResult res = client.putObject(por);
      return true;
    } catch (Exception e) {
      e.printStackTrace();
      return false;
    }
  }

  public static boolean downloadMultiPart(AmazonS3 client, S3PathInfo path, RandomAccessFile rf,
      Long partSize) {
    ObjectMetadata meta = client.getObjectMetadata(path.getBucket(), path.getPath());
    Long total = meta.getContentLength();
    ExecutorService pool = Executors.newFixedThreadPool(10);
//    long partSize = 10485760L;
    System.out.println(partSize);
    long start = 0L;
    long end;
    CountDownLatch cnt = new CountDownLatch((int) Math.ceil(total / (double) partSize));
    int x = 0;
    while (start < total) {
      if (total - start >= partSize) {
        end = start + partSize - 1;
      } else {
        end = total - 1;
      }
      final long finalEnd = end;
      final long finalStart = start;
      pool.submit(() -> {
        GetObjectRequest gor = new GetObjectRequest(path.getBucket(), path.getPath())
            .withRange(finalStart, finalEnd);
        S3ObjectInputStream oc = client.getObject(gor)
            .getObjectContent();

        try (InputStream buffer = new BufferedInputStream(oc)) {
          byte[] buf = new byte[1024];
          int len;
          long from = finalStart;
          while (true) {
            if ((len = buffer.read(buf)) == -1) {
              break;
            }
            synchronized (rf) {
              rf.seek(from);
              rf.write(buf, 0, len);
            }
            from += len;
          }
        } catch (IOException e) {
          throw new RuntimeException(e);
        }
        cnt.countDown();
      });

      start += partSize;
    }
    try {
      cnt.await();
      return true;
    } catch (InterruptedException e) {
      throw new RuntimeException(e);
    }
  }
}

